// App.js
import React, { useState, useEffect } from 'react';
import AuthService from './AuthService';
import Dashboard from './Dashboard';
import Login from './Login';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const initAuth = async () => {
      if (window.location.hash) {
        const tokens = AuthService.handleCallback();
        if (tokens) {
          setIsAuthenticated(true);
          const userData = await AuthService.getUserInfo();
          setUser(userData);
          window.history.replaceState({}, document.title, window.location.pathname);
        }
      } else {
        const token = AuthService.getAccessToken();
        if (token && !AuthService.isTokenExpired()) {
          setIsAuthenticated(true);
          const userData = await AuthService.getUserInfo();
          setUser(userData);
        }
      }
      setLoading(false);
    };

    initAuth();
  }, []);

  const handleLogin = () => {
    AuthService.login();
  };

  const handleLogout = () => {
    AuthService.logout();
    setIsAuthenticated(false);
    setUser(null);
  };

  if (loading) {
    return <div>Loading...</div>;
  }

  return (
    <div className="App">
      {isAuthenticated ? (
        <Dashboard user={user} onLogout={handleLogout} />
      ) : (
        <Login onLogin={handleLogin} />
      )}
    </div>
  );
}

export default App;

// AuthService.js
const AuthService = {
  config: {
    authorizationEndpoint: 'https://accounts.example.com/oauth/authorize',
    clientId: 'YOUR_CLIENT_ID',
    redirectUri: window.location.origin + '/callback',
    scope: 'openid profile email',
    userInfoEndpoint: 'https://accounts.example.com/oauth/userinfo'
  },

  login() {
    const state = this.generateRandomString(32);
    const nonce = this.generateRandomString(32);
    
    sessionStorage.setItem('oauth_state', state);
    sessionStorage.setItem('oauth_nonce', nonce);

    const params = new URLSearchParams({
      response_type: 'token',
      client_id: this.config.clientId,
      redirect_uri: this.config.redirectUri,
      scope: this.config.scope,
      state: state,
      nonce: nonce
    });

    window.location.href = `${this.config.authorizationEndpoint}?${params.toString()}`;
  },

  handleCallback() {
    const hash = window.location.hash.substring(1);
    const params = new URLSearchParams(hash);

    const accessToken = params.get('access_token');
    const tokenType = params.get('token_type');
    const expiresIn = params.get('expires_in');
    const state = params.get('state');
    const error = params.get('error');

    if (error) {
      console.error('OAuth error:', error);
      const errorDescription = params.get('error_description');
      alert(`Authentication failed: ${errorDescription || error}`);
      return null;
    }

    const savedState = sessionStorage.getItem('oauth_state');
    if (state !== savedState) {
      console.error('State mismatch');
      alert('Authentication failed: Invalid state parameter');
      return null;
    }

    sessionStorage.removeItem('oauth_state');
    sessionStorage.removeItem('oauth_nonce');

    if (accessToken) {
      const expiresAt = Date.now() + (parseInt(expiresIn) * 1000);
      
      localStorage.setItem('access_token', accessToken);
      localStorage.setItem('token_type', tokenType || 'Bearer');
      localStorage.setItem('expires_at', expiresAt.toString());

      return {
        accessToken,
        tokenType,
        expiresIn,
        expiresAt
      };
    }

    return null;
  },

  getAccessToken() {
    return localStorage.getItem('access_token');
  },

  getTokenType() {
    return localStorage.getItem('token_type') || 'Bearer';
  },

  isTokenExpired() {
    const expiresAt = localStorage.getItem('expires_at');
    if (!expiresAt) return true;
    return Date.now() >= parseInt(expiresAt);
  },

  async getUserInfo() {
    const token = this.getAccessToken();
    if (!token) return null;

    try {
      const response = await fetch(this.config.userInfoEndpoint, {
        headers: {
          'Authorization': `${this.getTokenType()} ${token}`
        }
      });

      if (!response.ok) {
        throw new Error('Failed to fetch user info');
      }

      return await response.json();
    } catch (error) {
      console.error('Error fetching user info:', error);
      return null;
    }
  },

  logout() {
    localStorage.removeItem('access_token');
    localStorage.removeItem('token_type');
    localStorage.removeItem('expires_at');
    sessionStorage.removeItem('oauth_state');
    sessionStorage.removeItem('oauth_nonce');
  },

  generateRandomString(length) {
    const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    const randomValues = new Uint8Array(length);
    window.crypto.getRandomValues(randomValues);
    return Array.from(randomValues)
      .map(v => charset[v % charset.length])
      .join('');
  },

  async makeAuthenticatedRequest(url, options = {}) {
    const token = this.getAccessToken();
    
    if (!token || this.isTokenExpired()) {
      throw new Error('No valid access token available');
    }

    const headers = {
      ...options.headers,
      'Authorization': `${this.getTokenType()} ${token}`
    };

    const response = await fetch(url, {
      ...options,
      headers
    });

    if (response.status === 401) {
      this.logout();
      window.location.reload();
    }

    return response;
  }
};

export default AuthService;

